import time
import logging


class Cache:
    def __init__(self, ttl=60):
        self.ttl = ttl
        self.store = {}

    def get(self, key):
        entry = self.store.get(key)
        if entry is None:
            return None
        if time.time() - entry[0] > self.ttl:
            del self.store[key]
            return None
        return entry[1]

    def set(self, key, value):
        self.store[key] = (time.time(), value)

    def clear(self):
        self.store = {}
        logging.info("cache cleared")

    def size(self):
        return len(self.store)

